+                    .sum::<u64>(),
+            )
+            .saturating_add(
+                self.iterators
+                    .iter()
+                    .map(Self::estimate_iterator_bytes)
+                    .sum::<u64>(),
+            )
+            .saturating_add(
+                self.generators
+                    .iter()
+                    .map(Self::estimate_generator_bytes)
+                    .sum::<u64>(),
+            )
+    }
